<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Kanban Board</title>
<style>
  :root {
    --bg: #f4f5f7;
    --col-bg: #ebecf0;
    --card-bg: #ffffff;
    --accent: #5b7fff;
    --text: #172b4d;
    --muted: #6b778c;
  }
  * { box-sizing: border-box; }
  body {
    margin: 0;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Arial, sans-serif;
    background: var(--bg);
    color: var(--text);
    padding: 24px;
  }
  h1 {
    margin: 0 0 20px;
    font-size: 22px;
  }
  .toolbar {
    display: flex;
    gap: 8px;
    margin-bottom: 24px;
  }
  #new-card {
    flex: 1;
    max-width: 400px;
    padding: 10px 12px;
    border: 1px solid #dfe1e6;
    border-radius: 6px;
    font-size: 14px;
  }
  #new-card:focus {
    outline: none;
    border-color: var(--accent);
    box-shadow: 0 0 0 2px rgba(91,127,255,0.2);
  }
  #add-card {
    padding: 10px 18px;
    background: var(--accent);
    color: white;
    border: none;
    border-radius: 6px;
    font-size: 14px;
    cursor: pointer;
    font-weight: 600;
  }
  #add-card:hover { background: #4a6ee0; }

  .board {
    display: grid;
    grid-template-columns: repeat(3, minmax(240px, 1fr));
    gap: 16px;
    max-width: 1100px;
  }
  .column {
    background: var(--col-bg);
    border-radius: 10px;
    padding: 12px;
    display: flex;
    flex-direction: column;
    min-height: 400px;
  }
  .column.drag-over {
    outline: 2px dashed var(--accent);
    outline-offset: -4px;
    background: #e0e4ff;
  }
  .col-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 4px 6px 12px;
    font-weight: 700;
    font-size: 13px;
    text-transform: uppercase;
    letter-spacing: 0.04em;
    color: var(--muted);
  }
  .count {
    background: #dfe1e6;
    color: var(--text);
    border-radius: 12px;
    padding: 2px 9px;
    font-size: 12px;
    font-weight: 700;
  }
  .cards {
    display: flex;
    flex-direction: column;
    gap: 8px;
    flex: 1;
    min-height: 60px;
  }
  .card {
    background: var(--card-bg);
    border-radius: 6px;
    padding: 10px 12px;
    box-shadow: 0 1px 2px rgba(9,30,66,0.25);
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 8px;
    cursor: grab;
    font-size: 14px;
    word-break: break-word;
  }
  .card:active { cursor: grabbing; }
  .card.dragging { opacity: 0.4; }
  .card-title {
    flex: 1;
  }
  .card-del {
    background: transparent;
    border: none;
    color: var(--muted);
    font-size: 16px;
    line-height: 1;
    cursor: pointer;
    padding: 2px 6px;
    border-radius: 4px;
  }
  .card-del:hover {
    background: #ffebe6;
    color: #de350b;
  }
</style>
</head>
<body>

<h1>Kanban Board</h1>

<div class="toolbar">
  <input type="text" id="new-card" placeholder="Add a new card to To Do...">
  <button id="add-card">Add Card</button>
</div>

<div class="board">
  <div class="column" id="col-todo" data-status="todo">
    <div class="col-header"><span>To Do</span><span class="count">0</span></div>
    <div class="cards" id="cards-todo"></div>
  </div>
  <div class="column" id="col-doing" data-status="doing">
    <div class="col-header"><span>Doing</span><span class="count">0</span></div>
    <div class="cards" id="cards-doing"></div>
  </div>
  <div class="column" id="col-done" data-status="done">
    <div class="col-header"><span>Done</span><span class="count">0</span></div>
    <div class="cards" id="cards-done"></div>
  </div>
</div>

<script>
(function () {
  const STORAGE_KEY = 'kanban-board-state';
  const columns = ['todo', 'doing', 'done'];

  function loadState() {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      if (!raw) return [];
      const parsed = JSON.parse(raw);
      if (!Array.isArray(parsed)) return [];
      return parsed;
    } catch (e) {
      return [];
    }
  }

  function saveState() {
    const cards = [];
    columns.forEach(status => {
      const container = document.getElementById('cards-' + status);
      Array.from(container.children).forEach(cardEl => {
        cards.push({ id: cardEl.dataset.id, title: cardEl.dataset.title, status: status });
      });
    });
    localStorage.setItem(STORAGE_KEY, JSON.stringify(cards));
  }

  function updateCounts() {
    columns.forEach(status => {
      const container = document.getElementById('cards-' + status);
      const col = document.getElementById('col-' + status);
      col.querySelector('.count').textContent = container.children.length;
    });
  }

  function makeId() {
    return 'c' + Math.random().toString(36).slice(2, 10) + Date.now().toString(36);
  }

  function createCardElement(id, title) {
    const card = document.createElement('div');
    card.className = 'card';
    card.draggable = true;
    card.dataset.id = id;
    card.dataset.title = title;

    const titleSpan = document.createElement('span');
    titleSpan.className = 'card-title';
    titleSpan.textContent = title;

    const delBtn = document.createElement('button');
    delBtn.className = 'card-del';
    delBtn.textContent = '\u00d7';
    delBtn.setAttribute('aria-label', 'Delete card');
    delBtn.addEventListener('click', function () {
      card.remove();
      updateCounts();
      saveState();
    });

    card.appendChild(titleSpan);
    card.appendChild(delBtn);

    card.addEventListener('dragstart', function (e) {
      card.classList.add('dragging');
      e.dataTransfer.setData('text/plain', id);
      e.dataTransfer.effectAllowed = 'move';
    });
    card.addEventListener('dragend', function () {
      card.classList.remove('dragging');
    });

    return card;
  }

  function addCard(status, title, id) {
    const container = document.getElementById('cards-' + status);
    const card = createCardElement(id || makeId(), title);
    container.appendChild(card);
  }

  function setupColumnDnD() {
    columns.forEach(status => {
      const col = document.getElementById('col-' + status);
      const container = document.getElementById('cards-' + status);

      col.addEventListener('dragover', function (e) {
        e.preventDefault();
        e.dataTransfer.dropEffect = 'move';
        col.classList.add('drag-over');
      });

      col.addEventListener('dragleave', function (e) {
        if (!col.contains(e.relatedTarget)) {
          col.classList.remove('drag-over');
        }
      });

      col.addEventListener('drop', function (e) {
        e.preventDefault();
        col.classList.remove('drag-over');
        const id = e.dataTransfer.getData('text/plain');
        const cardEl = document.querySelector('.card[data-id="' + id + '"]');
        if (cardEl) {
          container.appendChild(cardEl);
          updateCounts();
          saveState();
        }
      });
    });
  }

  function init() {
    const state = loadState();
    if (state.length) {
      state.forEach(item => {
        const status = columns.includes(item.status) ? item.status : 'todo';
        addCard(status, item.title, item.id);
      });
    }
    updateCounts();
    setupColumnDnD();

    const input = document.getElementById('new-card');
    const addBtn = document.getElementById('add-card');

    function handleAdd() {
      const text = input.value.trim();
      if (!text) return;
      addCard('todo', text);
      input.value = '';
      updateCounts();
      saveState();
      input.focus();
    }

    addBtn.addEventListener('click', handleAdd);
    input.addEventListener('keydown', function (e) {
      if (e.key === 'Enter') {
        handleAdd();
      }
    });
  }

  init();
})();
</script>

</body>
</html>
